__kernel void kernel_compute_flux(__global const int* elements_surrounding_elements, __global const float* normals, __global const float* variables, __global const float* ff_variable, __global float* fluxes, __global const float3* ff_flux_contribution_density_energy, __global const float3* ff_flux_contribution_momentum_x, __global const float3* ff_flux_contribution_momentum_y, __global const float3* ff_flux_contribution_momentum_z, int nelr) {
