// Helper function to calculate Euclidean distance squared
float euclid_dist_2(float *pt1, float *pt2, int numdims) {
    float ans = 0.0f;
    for (int i = 0; i < numdims; i++) {
        float diff = pt1[i] - pt2[i];
        ans += diff * diff;
    }
    return ans;
}

// Helper function to find the nearest cluster center
int find_nearest_point(float *pt, int nfeatures, float *clusters, int nclusters) {
    int index = 0;
    float min_dist = FLT_MAX;

    for (int i = 0; i < nclusters; i++) {
        float dist = euclid_dist_2(pt, &clusters[i * nfeatures], nfeatures);
        if (dist < min_dist) {
            min_dist = dist;
            index = i;
        }
    }
    return index;
}

