#ifndef FLT_MAX
#define FLT_MAX 3.40282347e+38
#endif

__attribute__((always_inline))
float euclid_dist_2(const float *pt1,
                    const float *pt2,
                    const int   numdims)
{
    int i;
    float ans = 0.0f;

    for (i = 0; i < numdims; i++) {
        float diff = pt1[i] - pt2[i];
        ans += diff * diff;
    }

    return ans;
}

int find_nearest_point(const float *pt,
                       const int   nfeatures,
                       const float *pts,
                       const int   npts,
                       const int   nfeatures_stride)
{
    int index = 0;
    float min_dist = FLT_MAX;
    int i;

    for (i = 0; i < npts; i++) {
        float dist = euclid_dist_2(pt, pts + (i * nfeatures_stride), nfeatures);
        if (dist < min_dist) {
            min_dist = dist;
            index = i;
        }
    }
    return index;
}

void kmeans_clustering_kernel(const float *feature,
                              const int   nfeatures,
                              const int   npoints,
                              const int   nclusters,
                              const float threshold,
                              int       *membership,
                              float     *clusters,
                              int       *new_centers_len,
                              float     *new_centers,
                              int       *partial_new_centers_len,
                              float     *partial_new_centers,
                              const int   nthreads,
                              float     *delta_out)
{
    int tid = get_thread_id();
    int i, j, k;
    float delta = 0.0f;
    int index;

    if (tid == 0) {
        for (i = 0; i < nthreads * nclusters; i++) {
            partial_new_centers_len[i] = 0;
        }
        for (i = 0; i < nthreads * nclusters * nfeatures; i++) {
            partial_new_centers[i] = 0.0f;
        }
    }

    #pragma omp parallel for reduction(+:delta)
    for (i = 0; i < npoints; i++) {
        index = find_nearest_point(feature + (i * nfeatures),
                                   nfeatures,
                                   clusters,
                                   nclusters,
                                   nfeatures);

        if (membership[i] != index) {
            delta += 1.0f;
        }

        membership[i] = index;

        partial_new_centers_len[tid * nclusters + index]++;
        for (j = 0; j < nfeatures; j++) {
            partial_new_centers[(tid * nclusters + index) * nfeatures + j] += feature[i * nfeatures + j];
        }
    }

    if (tid == 0) {
        for (i = 0; i < nclusters; i++) {
            for (j = 0; j < nthreads; j++) {
                new_centers_len[i] += partial_new_centers_len[j * nclusters + i];
                partial_new_centers_len[j * nclusters + i] = 0;
                for (k = 0; k < nfeatures; k++) {
                    new_centers[i * nfeatures + k] += partial_new_centers[(j * nclusters + i) * nfeatures + k];
                    partial_new_centers[(j * nclusters + i) * nfeatures + k] = 0.0f;
                }
            }
        }

        for (i = 0; i < nclusters; i++) {
            for (j = 0; j < nfeatures; j++) {
                if (new_centers_len[i] > 0) {
                    clusters[i * nfeatures + j] = new_centers[i * nfeatures + j] / (float)new_centers_len[i];
                }
                new_centers[i * nfeatures + j] = 0.0f;
            }
            new_centers_len[i] = 0;
        }
    }

    if (tid == 0) {
        *delta_out = delta;
    }
}

int cluster(int      numObjects,
            int      numAttributes,
            float    *attributes_flat,
            int      nclusters,
            float    threshold,
            float    *cluster_centres_flat)
{
    int    *membership;
    float  *tmp_cluster_centres;
    float  *new_centers;
    int    *new_centers_len;
    int    *partial_new_centers_len;
    float  *partial_new_centers;
    int    nthreads = 1;
    int    loop = 0;
    float  delta;
    int    i, j, k;
    int    n = 0;

    membership = (int*) malloc(numObjects * sizeof(int));
    tmp_cluster_centres = (float*) malloc(nclusters * numAttributes * sizeof(float));
    new_centers = (float*) calloc(nclusters * numAttributes, sizeof(float));
    new_centers_len = (int*) calloc(nclusters, sizeof(int));

    partial_new_centers_len = (int*) calloc(nthreads * nclusters, sizeof(int));
    partial_new_centers = (float*) calloc(nthreads * nclusters * numAttributes, sizeof(float));

    for (i = 0; i < nclusters; i++) {
        for (j = 0; j < numAttributes; j++) {
            tmp_cluster_centres[i * numAttributes + j] = attributes_flat[n * numAttributes + j];
        }
        n++;
    }

    for (i = 0; i < numObjects; i++) {
        membership[i] = -1;
    }

    do {
        delta = 0.0f;
        kmeans_clustering_kernel(attributes_flat,
                                 numAttributes,
                                 numObjects,
                                 nclusters,
                                 threshold,
                                 membership,
                                 tmp_cluster_centres,
                                 new_centers_len,
                                 new_centers,
                                 partial_new_centers_len,
                                 partial_new_centers,
                                 nthreads,
                                 &delta);
    } while (delta > threshold && loop++ < 500);

    for (i = 0; i < nclusters * numAttributes; i++) {
        cluster_centres_flat[i] = tmp_cluster_centres[i];
    }

    free(membership);
    free(tmp_cluster_centres);
    free(new_centers);
    free(new_centers_len);
    free(partial_new_centers_len);
    free(partial_new_centers);

    return 0;
}

