    // sum = sum_{k=0..BS-1} left[i,k] * top[k,j]
    // But original loop k=0..BS.
    // Wait, original:
    // for i=0..BS: for k=0..BS: for j=0..BS: sum[j] += left[i,k] * top[k,j]
    // Then BB -= sum[j].
    // This is a matrix multiplication: Block = Block - Left * Top.
    // Left is (BS x BS), Top is (BS x BS).
    // Result (BS x BS).
    // We can do standard MM.

    float sum = 0.0f;
    for (int k = 0; k < BLOCK_SIZE; k++) {
        sum += temp_left[i * BLOCK_SIZE + k] * temp_top[k * BLOCK_SIZE + j];
    }

    a[(i_global + i) * size + (j_global + j)] -= sum;
}

