void kernel_ecc(fp timeinst,
                fp* d_initvalu,
                fp* d_finavalu,
                fp* d_params,
                fp* d_com){

    fp CaDyad;
    fp CaSL;
    fp CaCyt;

    fp JCaDyad;
    fp JCaSL;
    fp JCaCyt;

    CaDyad = d_initvalu[35]*1e3;
    JCaDyad = cam(timeinst, d_initvalu, 46, d_params, 0, d_finavalu, CaDyad);

    CaSL = d_initvalu[36]*1e3;
    JCaSL = cam(timeinst, d_initvalu, 61, d_params, 5, d_finavalu, CaSL);

    CaCyt = d_initvalu[37]*1e3;
    JCaCyt = cam(timeinst, d_initvalu, 76, d_params, 10, d_finavalu, CaCyt);

    kernel_ecc_2(timeinst, d_initvalu, d_finavalu, 0, d_params);

    d_com[0] = JCaDyad;
    d_com[1] = JCaSL;
    d_com[2] = JCaCyt;

    kernel_fin(d_initvalu, 0, 46, 61, 76, d_params, d_finavalu, d_com[0], d_com[1], d_com[2]);

    int i;
    for(i=0; i<EQUATIONS; i++){
        if (isnan(d_finavalu[i]) == 1){ 
            d_finavalu[i] = 0.0001;
        }
        else if (isinf(d_finavalu[i]) == 1){ 
            d_finavalu[i] = 0.0001;
        }
    }
}

__attribute__((reqd_work_group_size(NUMBER_THREADS, 1, 1)))
void kernel_gpu_opencl(int timeinst,
                       cl_mem d_initvalu,
                       cl_mem d_finavalu,
                       cl_mem d_params,
                       cl_mem d_com){

    fp initvalu[EQUATIONS];
    fp finavalu[EQUATIONS];
    fp params[PARAMETERS];
    fp com[3];

    int i;

    for(i=0; i<EQUATIONS; i++){
        initvalu[i] = ((fp*)d_initvalu)[i];
        params[i] = ((fp*)d_params)[i];
    }

    kernel_ecc((fp)timeinst, initvalu, finavalu, params, com);

    for(i=0; i<EQUATIONS; i++){
        ((fp*)d_finavalu)[i] = finavalu[i];
    }
    ((fp*)d_com)[0] = com[0];
    ((fp*)d_com)[1] = com[1];
    ((fp*)d_com)[2] = com[2];
}

