#define MAX_ARGS 10
#define REC_LENGTH 49
#define REC_WINDOW 10
#define LATITUDE_POS 28
#define OPEN 10000

struct neighbor {
    char entry[REC_LENGTH];
    float dist;
};

__kernel void compute_distances(
    const char* sandbox,
    float* z,
    int rec_count,
    float target_lat,
    float target_long)
{
    int i = get_global_id(0);
    if (i >= rec_count) return;

    const char* rec_iter = sandbox + (i * REC_LENGTH + LATITUDE_POS - 1);

    // Parse latitude and longitude from the string record
    // Latitude starts at LATITUDE_POS-1, Longitude is 5 chars after
    char lat_str[10];
    char lon_str[10];

    // Extract latitude substring (approx 5 chars based on original atof usage)
    int idx = 0;
    while(idx < 9 && rec_iter[idx] != '\0' && rec_iter[idx] != ' ') {
        lat_str[idx] = rec_iter[idx];
        idx++;
    }
    lat_str[idx] = '\0';

    // Extract longitude substring
    const char* lon_ptr = rec_iter + 5;
    idx = 0;
    while(idx < 9 && lon_ptr[idx] != '\0' && lon_ptr[idx] != ' ') {
        lon_str[idx] = lon_ptr[idx];
        idx++;
    }
    lon_str[idx] = '\0';

    float tmp_lat = atof(lat_str);
    float tmp_long = atof(lon_str);

    float diff_lat = tmp_lat - target_lat;
    float diff_long = tmp_long - target_long;

    z[i] = sqrt((diff_lat * diff_lat) + (diff_long * diff_long));
}

__kernel void update_neighbors(
    const char* sandbox,
    const float* z,
    struct neighbor* neighbors,
    int rec_count,
    int k)
{
    int i = get_global_id(0);
    if (i >= rec_count) return;

    // Find max distance in current neighbors list
    float max_dist = -1.0f;
    int max_idx = 0;

    for (int j = 0; j < k; j++) {
        if (neighbors[j].dist > max_dist) {
            max_dist = neighbors[j].dist;
            max_idx = j;
        }
    }

    if (z[i] < neighbors[max_idx].dist) {
        // Copy record string
        for (int c = 0; c < REC_LENGTH; c++) {
            neighbors[max_idx].entry[c] = sandbox[i * REC_LENGTH + c];
        }
        neighbors[max_idx].dist = z[i];
    }
}

#define MAX_ARGS 10
#define REC_LENGTH 49
#define REC_WINDOW 10
#define LATITUDE_POS 28
#define OPEN 10000

struct neighbor {
    char entry[REC_LENGTH];
    float dist;
};

typedef struct {
    char sandbox[REC_LENGTH * REC_WINDOW];
    float target_lat;
    float target_long;
    int rec_count;
    int k;
    float z[REC_WINDOW];
    struct neighbor neighbors[MAX_ARGS];
} GlobalData;

kernel void compute_distances(GlobalData *gd) {
    int i = get_global_id(0);
    if (i >= gd->rec_count) return;

    char *rec_iter = gd->sandbox + (i * REC_LENGTH + LATITUDE_POS - 1);

    // Manual string to float conversion for latitude
    float tmp_lat = 0.0f;
    float lat_frac = 0.0f;
    float lat_div = 1.0f;
    int lat_sign = 1;
    int idx = 0;
    char c = rec_iter[idx];

    if (c == '-') { lat_sign = -1; idx++; c = rec_iter[idx]; }
    while (c >= '0' && c <= '9') {
        tmp_lat = tmp_lat * 10.0f + (c - '0');
        idx++; c = rec_iter[idx];
    }
    if (c == '.') {
        idx++; c = rec_iter[idx];
        while (c >= '0' && c <= '9') {
            lat_div *= 10.0f;
            lat_frac += (c - '0') / lat_div;
            idx++; c = rec_iter[idx];
        }
    }
    tmp_lat = (tmp_lat + lat_frac) * lat_sign;

    // Manual string to float conversion for longitude (offset by 5)
    char *rec_iter_long = rec_iter + 5;
    float tmp_long = 0.0f;
    float long_frac = 0.0f;
    float long_div = 1.0f;
    int long_sign = 1;
    idx = 0;
    c = rec_iter_long[idx];

    if (c == '-') { long_sign = -1; idx++; c = rec_iter_long[idx]; }
    while (c >= '0' && c <= '9') {
        tmp_long = tmp_long * 10.0f + (c - '0');
        idx++; c = rec_iter_long[idx];
    }
    if (c == '.') {
        idx++; c = rec_iter_long[idx];
        while (c >= '0' && c <= '9') {
            long_div *= 10.0f;
            long_frac += (c - '0') / long_div;
            idx++; c = rec_iter_long[idx];
        }
    }
    tmp_long = (tmp_long + long_frac) * long_sign;

    float diff_lat = tmp_lat - gd->target_lat;
    float diff_long = tmp_long - gd->target_long;
    gd->z[i] = sqrt((diff_lat * diff_lat) + (diff_long * diff_long));
}

kernel void update_neighbors(GlobalData *gd) {
    int i = get_global_id(0);
    if (i >= gd->rec_count) return;

    float max_dist = -1.0f;
    int max_idx = 0;

    for (int j = 0; j < gd->k; j++) {
        if (gd->neighbors[j].dist > max_dist) {
            max_dist = gd->neighbors[j].dist;
            max_idx = j;
        }
    }

    if (gd->z[i] < gd->neighbors[max_idx].dist) {
        // Copy record string
        for (int c = 0; c < REC_LENGTH - 1; c++) {
            gd->neighbors[max_idx].entry[c] = gd->sandbox[i * REC_LENGTH + c];
