    // Decimal point
    if (pos < idx + 6 && sandbox[pos] == '.') {
        pos++;
        while (pos < idx + 6 && sandbox[pos] >= '0' && sandbox[pos] <= '9') {
            frac = frac * 10.0f + (sandbox[pos] - '0');
            divisor *= 10.0f;
            pos++;
        }
    }

    tmp_lat = sign * (val + frac / divisor);

    // Parse longitude (offset +5 from latitude start)
    pos = idx + 5;
    sign = 1.0f;
    if (sandbox[pos] == '-') { sign = -1.0f; pos++; }
    else if (sandbox[pos] == '+') { pos++; }

    val = 0.0f;
    frac = 0.0f;
    divisor = 1.0f;

