    // Find max distance in current neighbors
    float max_dist = -1.0f;
    int max_idx = 0;

    for (int j = 0; j < k; j++) {
        if (neighbors[j].dist > max_dist) {
            max_dist = neighbors[j].dist;
            max_idx = j;
        }
    }

    if (z[i] < neighbors[max_idx].dist) {
