int findIndex_bin(double *CDF, int beginIndex, int endIndex, double value) {
    if (endIndex < beginIndex)
        return -1;
    int middleIndex = beginIndex + ((endIndex - beginIndex) / 2);

    if (CDF[middleIndex] >= value) {
        if (middleIndex == 0)
            return middleIndex;
        else if (CDF[middleIndex - 1] < value)
            return middleIndex;
        else if (CDF[middleIndex - 1] == value) {
            while (middleIndex > 0 && CDF[middleIndex - 1] == value)
                middleIndex--;
            return middleIndex;
        }
    }
    if (CDF[middleIndex] > value)
        return findIndex_bin(CDF, beginIndex, middleIndex + 1, value);
    return findIndex_bin(CDF, middleIndex - 1, endIndex, value);
}

int findIndex(double *CDF, int lengthCDF, double value) {
    int index = -1;
    int x;
    for (x = 0; x < lengthCDF; x++) {
        if (CDF[x] >= value) {
            index = x;
            break;
        }
    }
    if (index == -1) {
        return lengthCDF - 1;
    }
    return index;
}

